window.DMS_MAT_ACTIVE_KEY = 'dmssbx-materials-active-v1';
window.dmsMatKey = function(cat, sub, r){ return [cat, sub, r.g, r.code || ''].join('|'); };
window.dmsLoadActiveSet = function(){
  try { return new Set(JSON.parse(localStorage.getItem(window.DMS_MAT_ACTIVE_KEY) || '[]')); }
  catch (e) { return new Set(); }
};
window.dmsSaveActiveSet = function(s){
  try { localStorage.setItem(window.DMS_MAT_ACTIVE_KEY, JSON.stringify(Array.from(s))); } catch (e) {}
};
